ProductConfig = {}
ProductConfig.products = {}

function ProductConfig:init(config)
    self:initProduct(config)
end

function ProductConfig:initProduct(config)
    for i, v in pairs(config) do
        local item = {}
        item.id = tonumber(v.id)
        item.maxLv = tonumber(v.maxLv)
        item.headInfoLock = tostring(v.headInfoLock)
        item.headInfo = tostring(v.headInfo)
        item.headInfoForever = tostring(v.headInfoForever)
        item.actor = tostring(v.actor)
        item.actorBody = tostring(v.actorBody)
        item.actorBodyId = tonumber(v.actorBodyId)
        item.yaw = tonumber(v.yaw)
        item.type = tonumber(v.type)

        item.productIdList = {}
        local productIdList = StringUtil.split(tostring(v.productIdList), "#")
        if productIdList then
            for i = 1, #productIdList do
                table.insert(item.productIdList, tonumber(productIdList[i]))
            end
        end

        item.coinList = {}
        local coinList = StringUtil.split(tostring(v.coinList), "#")
        if coinList then
            for i = 1, #coinList do
                table.insert(item.coinList, tonumber(coinList[i]))
            end
        end

        item.priceList = {}
        local priceList = StringUtil.split(tostring(v.priceList), "#")
        if priceList then
            for i = 1, #priceList do
                table.insert(item.priceList, tonumber(priceList[i]))
            end
        end

        item.timeList = {}
        local timeList = StringUtil.split(tostring(v.timeList), "#")
        if timeList then
            for i = 1, #timeList do
                table.insert(item.timeList, tonumber(timeList[i]))
            end
        end

        item.adList = {}
        local adList = StringUtil.split(tostring(v.adList), "#")
        if adList then
            for i = 1, #adList do
                table.insert(item.adList, tonumber(adList[i]))
            end
        end

        item.adpriceList = {}
        local adpriceList = StringUtil.split(tostring(v.adpriceList), "#")
        if adpriceList then
            for i = 1, #adpriceList do
                table.insert(item.adpriceList, tonumber(adpriceList[i]))
            end
        end

        local actorPos = StringUtil.split(tostring(v.actorPos), "#")
        item.actorPos = VectorUtil.newVector3(actorPos[1], actorPos[2], actorPos[3])

        self.products[item.id] = item
    end
    table.sort(self.products, function ( a, b )
        return a.id < b.id
    end)
end

function ProductConfig:getMaxLevel(id)
    for i, v in pairs(self.products) do
        if v.id == id then
            return v.maxLv
        end
    end
    return 0
end

function ProductConfig:getIdByNpcLevel(id, level)
    for i, v in pairs(self.products) do
        if v.id == id then
            for k, Id in pairs(v.productIdList) do
                if k == level then
                    return Id
                end
            end
        end
